<?php
declare(strict_types=1);

if($path==='/contacts/import/template.csv'){
    require_permission('contacts.edit');header('Content-Type: text/csv; charset=UTF-8');header('Content-Disposition: attachment; filename="opencrm-contact-import-template.csv"');
    $out=fopen('php://output','wb');fputcsv($out,['First Name','Last Name','Email','Company','Job Title','Phone','Address','Website','Tags','Notes']);fputcsv($out,['Jane','Smith','jane@example.com','Example Company','Director','555-0100','123 Main Street','https://example.com','Prospect, Newsletter','Met at the annual conference.']);fclose($out);exit;
}
if($path!=='/contacts/import')return;
require_permission('contacts.edit');
if($method==='POST'){
    verify_csrf();
    $confirm=post('action')==='confirm';
    if($confirm){$token=(string)post('preview_token');$preview=$_SESSION['contact_import_preview'][$token]??null;if(!$preview||!is_file($preview['path'])){flash('error','That import preview expired. Upload the file again.');redirect('/contacts/import');}$upload=['tmp_name'=>$preview['path'],'name'=>$preview['name'],'size'=>filesize($preview['path']),'error'=>UPLOAD_ERR_OK];unset($_SESSION['contact_import_preview'][$token]);}
    else{$upload=$_FILES['contacts']??null;if(!$upload||$upload['error']!==UPLOAD_ERR_OK){flash('error','Choose a contact file to import.');redirect('/contacts/import');}}
    $ext=strtolower(pathinfo($upload['name'],PATHINFO_EXTENSION));
    if($upload['size']>8*1024*1024||!in_array($ext,['xlsx','csv','tsv'],true)){flash('error','Use an XLSX, CSV, or TSV file no larger than 8 MB.');redirect('/contacts/import');}
    if(!$confirm){try{$parsed=attendee_rows($upload['tmp_name'],$ext);$headers=array_shift($parsed)??[];$normalized=[];foreach($headers as $i=>$header)$normalized[preg_replace('/[^a-z]/','',strtolower(trim((string)$header)))]=$i;$firstIndex=$normalized['firstname']??$normalized['first']??null;$lastIndex=$normalized['lastname']??$normalized['last']??null;$emailIndex=$normalized['email']??$normalized['emailaddress']??null;if($firstIndex===null||$lastIndex===null)throw new RuntimeException('The file needs First Name and Last Name columns.');$previewRows=[];$counts=['new'=>0,'update'=>0,'possible_duplicate'=>0,'invalid'=>0];$emailStmt=db()->prepare('SELECT id FROM contacts WHERE LOWER(email)=? LIMIT 2');foreach($parsed as $row){$first=trim((string)($row[$firstIndex]??''));$last=trim((string)($row[$lastIndex]??''));$email=strtolower(trim((string)($row[$emailIndex??-1]??'')));$status='new';$detail='New contact';if($first===''||$last===''||($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL))){$status='invalid';$detail='Missing name or invalid email';}elseif($email!==''){$emailStmt->execute([$email]);$matches=$emailStmt->fetchAll();if(count($matches)===1){$status='update';$detail='Matches existing contact by email';}elseif(count($matches)>1){$status='possible_duplicate';$detail='Multiple contacts use this email';}}$counts[$status]++;if(count($previewRows)<300)$previewRows[]=compact('first','last','email','status','detail');}$token=bin2hex(random_bytes(20));$dir=dirname(__DIR__).'/storage/uploads';$path=$dir.'/import-preview-'.$token.'.'.$ext;if(!move_uploaded_file($upload['tmp_name'],$path))throw new RuntimeException('Could not preserve the uploaded preview.');$_SESSION['contact_import_preview'][$token]=['path'=>$path,'name'=>basename($upload['name']),'created_at'=>time()];layout('Preview contact import',function()use($previewRows,$counts,$token){?><div class="actions"><h1 style="margin:0">Preview contact import</h1><span class="spacer"></span><a class="btn secondary" href="/contacts/import">Cancel</a></div><div class="grid"><div class="card"><div class="metric"><?=$counts['new']?></div>New contacts</div><div class="card"><div class="metric"><?=$counts['update']?></div>Existing contacts updated</div><div class="card"><div class="metric"><?=$counts['possible_duplicate']?></div>Possible duplicates</div><div class="card"><div class="metric"><?=$counts['invalid']?></div>Invalid rows</div></div><div class="card"><p class="muted">Nothing has been imported yet. Review the analysis below, then confirm to create contacts, update matches, and add tags and notes.</p><table><thead><tr><th>Name</th><th>Email</th><th>Planned action</th></tr></thead><tbody><?php foreach($previewRows as $row):?><tr><td><?=e($row['first'].' '.$row['last'])?></td><td><?=e($row['email'])?></td><td><strong><?=e(ucwords(str_replace('_',' ',$row['status'])))?></strong><br><span class="muted"><?=e($row['detail'])?></span></td></tr><?php endforeach?></tbody></table><?php if(array_sum($counts)>count($previewRows)):?><p class="muted">Showing the first <?=count($previewRows)?> rows.</p><?php endif?></div><form class="card actions" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="confirm"><input type="hidden" name="preview_token" value="<?=e($token)?>"><strong>Ready to import?</strong><span class="spacer"></span><a class="btn secondary" href="/contacts/import">Cancel</a><button>Confirm import</button></form><?php });exit;}catch(Throwable $e){flash('error','Preview failed: '.$e->getMessage());redirect('/contacts/import');}}
    try{
        $rows=attendee_rows($upload['tmp_name'],$ext);$headers=array_shift($rows)??[];$aliases=['firstname'=>'first_name','first'=>'first_name','lastname'=>'last_name','last'=>'last_name','email'=>'email','emailaddress'=>'email','company'=>'company','organization'=>'company','jobtitle'=>'job_title','title'=>'job_title','phone'=>'phone','phonenumber'=>'phone','address'=>'address','streetaddress'=>'address','website'=>'website','url'=>'website','tags'=>'tags','tag'=>'tags','notes'=>'notes','note'=>'notes','contactnotes'=>'notes'];$map=[];
        foreach($headers as $i=>$header){$key=preg_replace('/[^a-z]/','',strtolower(trim((string)$header)));if(isset($aliases[$key]))$map[$aliases[$key]]=$i;}
        if(!isset($map['first_name'],$map['last_name']))throw new RuntimeException('The file needs First Name and Last Name columns.');
        $result=['created'=>0,'updated'=>0,'skipped'=>0,'failed'=>0];
        foreach($rows as $row){$get=fn(string $key)=>trim((string)($row[$map[$key]??-1]??''));$first=$get('first_name');$last=$get('last_name');$email=strtolower($get('email'));if($first===''||$last===''){$result['skipped']++;continue;}if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL)){$result['failed']++;continue;}
            try{$contactId=0;if($email!==''){$s=db()->prepare('SELECT id FROM contacts WHERE LOWER(email)=? ORDER BY id LIMIT 1');$s->execute([$email]);$contactId=(int)$s->fetchColumn();}if($contactId&&contact_access($contactId)==='hidden'){$result['skipped']++;continue;}
                $values=['first_name'=>$first,'last_name'=>$last,'email'=>$email,'company'=>$get('company'),'job_title'=>$get('job_title'),'phone'=>$get('phone'),'address'=>$get('address'),'website'=>$get('website')];
                if($contactId){$existingStmt=db()->prepare('SELECT * FROM contacts WHERE id=?');$existingStmt->execute([$contactId]);$existing=$existingStmt->fetch();if(!$existing||!can_edit_record($existing)){$result['skipped']++;continue;}$sets=[];$params=[];foreach($values as $field=>$value)if($value!==''){$sets[]="$field=?";$params[]=$value;}if($sets){$params[]=$contactId;db()->prepare('UPDATE contacts SET '.implode(',',$sets).' WHERE id=?')->execute($params);}$result['updated']++;}
                else{db()->prepare('INSERT INTO contacts(first_name,last_name,email,company,job_title,phone,address,website,created_by,owner_id) VALUES(?,?,?,?,?,?,?,?,?,?)')->execute([$first,$last,$email?:null,$values['company']?:null,$values['job_title']?:null,$values['phone']?:null,$values['address']?:null,$values['website']?:null,user()['id'],user()['id']]);$contactId=(int)db()->lastInsertId();apply_user_default_tags($contactId,user()['id']);$result['created']++;}
                $tagNames=preg_split('/[,;|]+/',$get('tags'),-1,PREG_SPLIT_NO_EMPTY);$tagStmt=db()->prepare("INSERT INTO tags(name,color) VALUES(?,'#546e7a') ON DUPLICATE KEY UPDATE id=LAST_INSERT_ID(id)");$linkStmt=db()->prepare('INSERT IGNORE INTO contact_tags(contact_id,tag_id) VALUES(?,?)');foreach($tagNames as $tagName){$tagName=trim($tagName);if($tagName===''||mb_strlen($tagName)>100)continue;$tagStmt->execute([$tagName]);$linkStmt->execute([$contactId,(int)db()->lastInsertId()]);}$note=$get('notes');if($note!=='')db()->prepare('INSERT INTO notes(contact_id,user_id,body) VALUES(?,?,?)')->execute([$contactId,user()['id'],$note]);
            }catch(Throwable){$result['failed']++;}
        }
        audit('import_contacts','contact',null,$result);if($confirm)@unlink($upload['tmp_name']);flash('success',"Import complete: {$result['created']} created, {$result['updated']} updated, {$result['skipped']} skipped, {$result['failed']} failed.");redirect('/contacts');
    }catch(Throwable $e){flash('error','Import failed: '.$e->getMessage());redirect('/contacts/import');}
}
layout('Import contacts',function(){?><div class="actions"><h1 style="margin:0">Import contacts</h1><span class="spacer"></span><a class="btn secondary" href="/contacts/import/template.csv">Download CSV template</a><a class="btn secondary" href="/contacts">Back to contacts</a></div><div class="card"><h2>Accepted columns</h2><p><strong>Required:</strong> First Name, Last Name</p><p><strong>Optional:</strong> Email, Company, Job Title, Phone, Address, Website, Tags, Notes</p><p class="muted">Existing contacts are matched by email and updated with non-empty imported values. A Notes value is added as a contact note attributed to the importing user. Tags may be separated by commas, semicolons, or vertical bars.</p></div><form class="card" method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Contact file (XLSX, CSV, or TSV; maximum 8 MB)<input type="file" name="contacts" accept=".xlsx,.csv,.tsv" required></label><button>Import contacts</button></form><?php });exit;
